import{V as o}from"./chunks/theme.B_a2YKhU.js";import{c as t,o as i,j as a,a2 as n,a as s,G as r,k as l}from"./chunks/framework.DDIT__tB.js";const d={class:"tip custom-block"},f=JSON.parse('{"title":"📊 Model: (InformationFlow-WebRTC-no-violation)","description":"","frontmatter":{},"headers":[],"relativePath":"examples/models/dfd/IF-WebRTC-no-violation.md","filePath":"examples/models/dfd/IF-WebRTC-no-violation.md"}'),c={name:"examples/models/dfd/IF-WebRTC-no-violation.md"},u=Object.assign(c,{setup(h){return(p,e)=>(i(),t("div",null,[e[2]||(e[2]=a("h1",{id:"📊-model-informationflow-webrtc-no-violation",tabindex:"-1"},[s("📊 Model: (InformationFlow-WebRTC-no-violation) "),a("a",{class:"header-anchor",href:"#📊-model-informationflow-webrtc-no-violation","aria-label":'Permalink to "📊 Model: (InformationFlow-WebRTC-no-violation)"'},"​")],-1)),a("div",d,[e[0]||(e[0]=a("p",{class:"custom-block-title"},"Available Online",-1)),e[1]||(e[1]=a("p",null,"This model is available to view using the online editor!",-1)),r(l(o),{text:"Open In Online Editor",href:"https://editor.dataflowanalysis.org/?file=https://raw.githubusercontent.com/DataFlowAnalysis/DataFlowAnalysis/refs/heads/main/bundles/org.dataflowanalysis.examplemodels/scenarios/dfd/IF-WebRTC-no-violation/WebRTC-no-violation.json"})]),e[3]||(e[3]=n('<h2 id="🔗-link-to-original-paper-article" tabindex="-1">🔗 Link to Original Paper/Article <a class="header-anchor" href="#🔗-link-to-original-paper-article" aria-label="Permalink to &quot;🔗 Link to Original Paper/Article&quot;">​</a></h2><p><a href="https://ieeexplore.ieee.org/document/8703905" target="_blank" rel="noreferrer">View Source</a><a href="https://github.com/DataFlowAnalysis/DataFlowAnalysis/tree/main/bundles/org.dataflowanalysis.examplemodels/scenarios/dfd/IF-WebRTC-no-violation" target="_blank" rel="noreferrer">Open Example Model in Example Models Bundle</a></p><h2 id="📝-short-description" tabindex="-1">📝 Short Description <a class="header-anchor" href="#📝-short-description" aria-label="Permalink to &quot;📝 Short Description&quot;">​</a></h2><p>The case covers a simplified version of the WebRTC protocol.</p><h2 id="🔤-abbreviations" tabindex="-1">🔤 Abbreviations <a class="header-anchor" href="#🔤-abbreviations" aria-label="Permalink to &quot;🔤 Abbreviations&quot;">​</a></h2><ul><li><code>WebRTC</code>: Web Real-Time Communication</li><li><code>STUN</code>: Session Traversal Utilities for NAT</li><li><code>NAT</code>: Network Address Translator</li></ul><h2 id="📖-extensive-description" tabindex="-1">📖 Extensive Description <a class="header-anchor" href="#📖-extensive-description" aria-label="Permalink to &quot;📖 Extensive Description&quot;">​</a></h2><p><strong>Alice</strong> and <strong>Bob</strong> want to communicate. They exchange ports via STUN servers (<strong>publish_port</strong> and <strong>receive_port</strong>) and exchange session data via a signaling server (<strong>dispatch_initial_session_data</strong> and <strong>dispatch_response_session_data</strong>) to initiate a session. These servers are in the <strong>Zone</strong> <code>Attack</code>. After that, they can send and receive media by <strong>create_media_package</strong> and <strong>unpack_media_package</strong>. The exchanged session data and media is encrypted. Encrypted data flows have a <strong>Level</strong> of <code>Low</code> but also a ContainedClassification which indicates the true Level of the unencrypted flow.</p><h2 id="🏷️-label-description" tabindex="-1">🏷️ Label Description <a class="header-anchor" href="#🏷️-label-description" aria-label="Permalink to &quot;🏷️ Label Description&quot;">​</a></h2><h3 id="🗂️-data-labels" tabindex="-1">🗂️ Data Labels: <a class="header-anchor" href="#🗂️-data-labels" aria-label="Permalink to &quot;🗂️ Data Labels:&quot;">​</a></h3><ul><li><strong>Level</strong>: There are two types of levels: <code>High</code> and <code>Low</code>.</li><li><strong>ContainedClassification</strong>: This label marks the <strong>Level</strong> of an encrypted data flow. It can be <code>High</code> or <code>Low</code>.</li></ul><h3 id="🏷️-node-labels" tabindex="-1">🏷️ Node Labels: <a class="header-anchor" href="#🏷️-node-labels" aria-label="Permalink to &quot;🏷️ Node Labels:&quot;">​</a></h3><ul><li><strong>Zone</strong>: There are two zones in this model: <code>Attack</code> and <code>Trust</code>. A node always part of one of these zones.</li></ul><h2 id="⚠️-constraints" tabindex="-1">⚠️ Constraints <a class="header-anchor" href="#⚠️-constraints" aria-label="Permalink to &quot;⚠️ Constraints&quot;">​</a></h2><h3 id="safety" tabindex="-1">Safety <a class="header-anchor" href="#safety" aria-label="Permalink to &quot;Safety&quot;">​</a></h3><p>The fundamental requirement is that system parts or actors in the attack zone must not have access to data classified High:</p><ul><li><code>Safety: data Level.High neverFlows vertex Zone.Attack</code></li></ul><h2 id="🚨-violations" tabindex="-1">🚨 Violations <a class="header-anchor" href="#🚨-violations" aria-label="Permalink to &quot;🚨 Violations&quot;">​</a></h2><p>None.</p>',19))]))}});export{f as __pageData,u as default};
